import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { FaBuilding, FaUsers, FaCalendarAlt } from 'react-icons/fa';

const AdminDashboard = () => {
  const [stats, setStats] = useState({
    totalBranches: 0,
    totalStaff: 0,
    totalBookings: 0
  });

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const [branches, users, bookings] = await Promise.all([
        axios.get('http://localhost:5000/api/branches'),
        axios.get('http://localhost:5000/api/users'),
        axios.get('http://localhost:5000/api/bookings')
      ]);

      const staff = users.data.data.filter(u => ['staff', 'branch_head'].includes(u.role));

      setStats({
        totalBranches: branches.data.data.length,
        totalStaff: staff.length,
        totalBookings: bookings.data.data.length
      });
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  return (
    <div>
      <h1>Admin Dashboard</h1>
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon blue">
            <FaBuilding />
          </div>
          <div className="stat-info">
            <h3>Total Branches</h3>
            <p>{stats.totalBranches}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon green">
            <FaUsers />
          </div>
          <div className="stat-info">
            <h3>Total Staff</h3>
            <p>{stats.totalStaff}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon orange">
            <FaCalendarAlt />
          </div>
          <div className="stat-info">
            <h3>Total Bookings</h3>
            <p>{stats.totalBookings}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
